content.content:
["/bin/bash","-c","if [ "$POD_NAME" = "crdb-cluster-1" ]; then
  HTTP_ADDR="127.0.0.1:8080";
else
  HTTP_ADDR="0.0.0.0:8080";
fi; exec /cockroach/cockroach start --logtostderr=INFO --insecure --advertise-host=$(POD_NAME).crdb-cluster.$(POD_NAMESPACE).svc.cluster.local --http-addr=${HTTP_ADDR} --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257"]

tool_use_result.stdout:
["/bin/bash","-c","if [ "$POD_NAME" = "crdb-cluster-1" ]; then
  HTTP_ADDR="127.0.0.1:8080";
else
  HTTP_ADDR="0.0.0.0:8080";
fi; exec /cockroach/cockroach start --logtostderr=INFO --insecure --advertise-host=$(POD_NAME).crdb-cluster.$(POD_NAMESPACE).svc.cluster.local --http-addr=${HTTP_ADDR} --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257"]

input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command/2",
    "value": "exec /cockroach/cockroach start --logtostderr=INFO --insecure --advertise-host=$(POD_NAME).crdb-cluster.$(POD_NAMESPACE).svc.cluster.local --http-addr=0.0.0.0:8080 --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257"
  }
]' 2>&1
